const response = $input.first().json;
const events = Array.isArray(response?.events) ? response.events : [];

const threshold = Number($env.AO_OS_AUTH_FAILURE_THRESHOLD || 5);
const windowMinutes = Number($env.AO_OS_AUTH_ANOMALY_WINDOW_MINUTES || 15);
const cooldownMinutes = Number($env.AO_OS_AUTH_ALERT_COOLDOWN_MINUTES || 30);

const now = new Date();
const cutoff = new Date(now.getTime() - windowMinutes * 60 * 1000);
const polledAt = response?.lastPolledAt || now.toISOString();

const staticData = $getWorkflowStaticData('global');
if (!staticData.authAnomalyLastAlertAt || typeof staticData.authAnomalyLastAlertAt !== 'object') {
  staticData.authAnomalyLastAlertAt = {};
}
const cooldownStore = staticData.authAnomalyLastAlertAt;

const failedAuthEvents = events.filter((event) => {
  if (event?.type !== 'AuthEvent') return false;
  if (event?.data?.eventType !== 'auth.login_failed') return false;

  const occurredAt = new Date(event.occurredAt);
  if (Number.isNaN(occurredAt.getTime())) return false;

  return occurredAt >= cutoff;
});

const grouped = new Map();

for (const event of failedAuthEvents) {
  const data = event?.data || {};
  const identityKey = String(data.memberId || data.attemptedEmail || data.ipAddress || 'unknown');

  if (!grouped.has(identityKey)) {
    grouped.set(identityKey, {
      identityKey,
      memberId: data.memberId || null,
      attemptedEmail: data.attemptedEmail || null,
      ipAddress: data.ipAddress || null,
      count: 0,
      reasonCounts: {},
      recent: []
    });
  }

  const row = grouped.get(identityKey);
  row.count += 1;

  const reason = String(data.failureReasonCode || 'UNKNOWN');
  row.reasonCounts[reason] = (row.reasonCounts[reason] || 0) + 1;

  row.recent.push({
    id: event.id,
    occurredAt: event.occurredAt,
    reason,
    ipAddress: data.ipAddress || null,
    attemptedEmail: data.attemptedEmail || null
  });
}

const anomalies = Array.from(grouped.values())
  .filter((group) => group.count >= threshold)
  .map((group) => {
    group.recent.sort((a, b) => new Date(b.occurredAt).getTime() - new Date(a.occurredAt).getTime());
    group.recent = group.recent.slice(0, 10);

    const reasonSummary = Object.entries(group.reasonCounts)
      .map(([reason, count]) => `${reason}:${count}`)
      .join(', ');

    const title = `Auth anomaly: ${group.count} failed logins in ${windowMinutes}m (${group.identityKey})`.slice(0, 200);

    const lastAlertAtRaw = cooldownStore[group.identityKey];
    const lastAlertAt = lastAlertAtRaw ? new Date(lastAlertAtRaw) : null;
    const withinCooldown = lastAlertAt && !Number.isNaN(lastAlertAt.getTime()) && (now.getTime() - lastAlertAt.getTime()) < cooldownMinutes * 60 * 1000;

    const suppressEmail = Boolean(withinCooldown);
    const suppressionReason = suppressEmail
      ? `Suppressed duplicate anomaly in ${cooldownMinutes}m cooldown`
      : null;

    if (!suppressEmail) {
      cooldownStore[group.identityKey] = now.toISOString();
    }

    return {
      type: 'auth.login_failed.anomaly',
      severity: 'critical',
      status: 'open',
      occurredAt: polledAt,
      threshold,
      windowMinutes,
      cooldownMinutes,
      failureCount: group.count,
      identityKey: group.identityKey,
      memberId: group.memberId,
      attemptedEmail: group.attemptedEmail,
      ipAddress: group.ipAddress,
      reasonSummary,
      recentFailures: group.recent,
      suppressEmail,
      suppressionReason,
      lastAlertAt: lastAlertAtRaw || null,
      notionPayload: {
        parent: {
          database_id: $env.NOTION_SECURITY_ALERT_DB_ID || $env.NOTION_OPERATIONAL_LOG_DB_ID
        },
        properties: {
          Title: {
            title: [{ text: { content: title } }]
          },
          'Event Type': {
            select: { name: 'AuthEvent' }
          },
          Status: {
            select: { name: suppressEmail ? 'Anomaly Suppressed' : 'Anomaly' }
          },
          Severity: {
            select: { name: 'critical' }
          },
          Timestamp: {
            date: { start: String(polledAt) }
          },
          'Member ID': {
            rich_text: group.memberId ? [{ text: { content: String(group.memberId) } }] : []
          },
          'Denial Reason': {
            rich_text: reasonSummary ? [{ text: { content: reasonSummary.slice(0, 1900) } }] : []
          },
          'Raw Data': {
            rich_text: [{
              text: {
                content: JSON.stringify({
                  threshold,
                  windowMinutes,
                  cooldownMinutes,
                  failureCount: group.count,
                  identityKey: group.identityKey,
                  attemptedEmail: group.attemptedEmail,
                  ipAddress: group.ipAddress,
                  suppressEmail,
                  suppressionReason,
                  lastAlertAt: lastAlertAtRaw || null,
                  recentFailures: group.recent
                }).slice(0, 1900)
              }
            }]
          },
          'Polled At': {
            date: { start: String(polledAt) }
          }
        }
      },
      emailSubject: `AO OS Auth Anomaly: ${group.count} failed logins (${group.identityKey})`,
      emailBody: `<h2>Auth Anomaly Detected</h2>
<table style="border-collapse:collapse;width:100%;font-family:sans-serif;font-size:14px">
  <tr><td style="padding:6px 12px;background:#f5f5f5;font-weight:bold">Identity</td><td style="padding:6px 12px">${group.identityKey}</td></tr>
  <tr><td style="padding:6px 12px;background:#f5f5f5;font-weight:bold">Failure Count</td><td style="padding:6px 12px">${group.count}</td></tr>
  <tr><td style="padding:6px 12px;background:#f5f5f5;font-weight:bold">Window</td><td style="padding:6px 12px">${windowMinutes} minutes</td></tr>
  <tr><td style="padding:6px 12px;background:#f5f5f5;font-weight:bold">Threshold</td><td style="padding:6px 12px">${threshold}</td></tr>
  <tr><td style="padding:6px 12px;background:#f5f5f5;font-weight:bold">Cooldown</td><td style="padding:6px 12px">${cooldownMinutes} minutes</td></tr>
  <tr><td style="padding:6px 12px;background:#f5f5f5;font-weight:bold">Reasons</td><td style="padding:6px 12px">${reasonSummary || 'UNKNOWN'}</td></tr>
</table>
<h3>Recent failures</h3>
<pre style="white-space:pre-wrap">${JSON.stringify(group.recent, null, 2)}</pre>`
    };
  });

return anomalies.map((json) => ({ json }));
